public void importSalesContractsLines(ETGSalesAgreementUploaderContract  _contract)
{
    #OCCRetryCount

    try
    {
        if (_contract.parmStorageResult() != conNull())
        {
            FileUploadTemporaryStorageResult fileUploadResultLoc = new FileUploadTemporaryStorageResult();
            fileUploadResultLoc.unpack(_contract.parmStorageResult());
            if (fileUploadResultLoc != null && fileUploadResultLoc.getUploadStatus())
            {
                stream = fileUploadResultLoc.openResult();

                using (ExcelPackage Package = new ExcelPackage(stream))
                {
                    int                         rowCount, i,columncount,j;
                    Package.Load(stream);
                    ExcelWorksheet              worksheet   = package.get_Workbook().get_Worksheets().get_Item(1);
                    OfficeOpenXml.ExcelRange    range       = worksheet.Cells;
                    rowCount                                = (worksheet.Dimension.End.Row) - (worksheet.Dimension.Start.Row)  + 1;
                    columncount                             = (worksheet.Dimension.End.Column);
                    for (i = 2; i<= rowCount; i++)
                    {
                        try
                        {
                            this.initilizeLine(range, i);
                            this.createLines();
                        }
                        catch
                        {
                            warning(ETGSalesOrderUploaderService::getError());
                            continue;
                        }
                    }
                }
            }
            else
            {
                throw error(strfmt("@SYS62207",filename));
            }
        }
    }

    catch (Exception::Deadlock)
    {
        retry;
    }

    catch (Exception::UpdateConflict)
    {
        if (appl.ttsLevel() == 0)
        {
            if (xSession::currentRetryCount() >= #RetryNum)
            {
                throw Exception::UpdateConflictNotRecovered;
            }
            else
            {
                retry;
            }
        }
        else
        {
            throw Exception::UpdateConflict;
        }
    }
}

public void initilizeLine(OfficeOpenXml.ExcelRange range, int i)
{
    salesNumberSequenceLoc    = range.get_Item(i, 1).value;
    lineNum                   = range.get_Item(i, 2).value;
    ItemId                    = range.get_Item(i, 3).value;
    name                      = range.get_Item(i, 4).value;
    configId                  = range.get_Item(i, 5).value;
    InventSizeId              = range.get_Item(i, 6).value;
    InventColorId             = range.get_Item(i, 7).value;
    InventStyleId             = range.get_Item(i, 8).value;
    InventSiteId              = range.get_Item(i, 9).value;
    InventLocationId          = range.get_Item(i, 10).value;
    wMSLocationId             = range.get_Item(i, 11).value;
    CommitedQuantity          = range.get_Item(i, 12).value;
    ProductUnitOfMeasure      = range.get_Item(i, 13).value;
    NetAmount                 = range.get_Item(i, 14).value;
    LineDiscountPercent       = range.get_Item(i, 15).value;
    PricePerUnit              = range.get_Item(i, 16).value;
    ExpirationDate            = str2Date(range.get_Item(i, 17).Text.ToString(), 213);
    LineDiscountAmount        = range.get_Item(i, 18).value;
    PriceUnit                 = range.get_Item(i, 19).value;
    IsPriceInformationMandatory = range.get_Item(i, 20).value;
    ETGPriceTolerance         = range.get_Item(i, 21).value;
   ETG_ItemAlternativeName   = range.get_Item(i, 22).value;
    ETG_IsGrossWeight         = range.get_Item(i, 23).value;
    ETG_PriceType             = range.get_Item(i, 24).value;
    ETGPriceCondition         = range.get_Item(i, 25).value;
    ETGPremiumPrice           = range.get_Item(i, 26).value;
    ETGFuturePrice            = range.get_Item(i, 27).value;
    ETG_UnderDeliveryPct      = range.get_Item(i, 28).value;
    ETG_OverDeliveryPct       = range.get_Item(i, 29).value;
    QuantityConditions         = range.get_Item(i, 30).value;
    ETGPortOfLoading           = range.get_Item(i, 31).value;
    ETGPortOfLoadingDesc       = range.get_Item(i, 32).value;
    ETGPortOfDischarge         = range.get_Item(i, 33).value;
    ETGPortOfDischargeDesc     = range.get_Item(i, 34).value;
    ETGFinalPlaceOfDelivery    = range.get_Item(i, 35).value;
    ETG_ToleranceAction        = range.get_Item(i, 36).value;
    ETG_ReleaseOrderLowerLimit = range.get_Item(i, 37).value;
    ETG_ReleaseOrderUpperLimit = range.get_Item(i, 38).value;
    BusinessUnit               = range.get_Item(i, 39).value;
    Contract                   = range.get_Item(i, 40).value;
    costcenter                 = range.get_Item(i, 41).value;
    InterCompany               = range.get_Item(i, 42).value;
    Items                      = range.get_Item(i, 43).value;
    Line_of_Business           = range.get_Item(i, 44).value;
    MainCommodity              = range.get_Item(i, 45).value;
    Plant_Warehouse_Office     = range.get_Item(i, 46).value;
    SubCommodity               = range.get_Item(i, 47).value;
    TraderEmployee             = range.get_Item(i, 48).value;
    Vertical                   = range.get_Item(i, 49).value;
    maxInforced                = range.get_Item(i, 50).value;
}

public static str getError()
{
    SysInfologEnumerator    sysInfologEnumerator;
    SysInfologMessageStruct infoMessageStruct;
    str                     logMessage;
    str                           logString;
    str                          ret;
    int                          i;
    #Define.NewLine('\n')
    sysInfologEnumerator = SysInfologEnumerator::newData(infolog.infologData());
    while (sysInfologEnumerator.moveNext())
    {
        i = 1;
        if (logMessage)
        {
            logMessage += #Newline;
        }
        infoMessageStruct = SysInfologMessageStruct::construct(sysInfologEnumerator.currentMessage());

        while (i <= infoMessageStruct.prefixDepth())
        {
            logString = logString + infoMessageStruct.preFixTextElement(i) + '. ';
            i++;
        }

        logString = logString + infoMessageStruct.message();
        logMessage = logMessage + infoMessageStruct.message();
    }

    infolog().clear();

    return logMessage;
}

public void createLines()
{
    SalesAgreementLineEntity      salesAgreementLine;
    SalesAgreementHeaderEntity    salesAgreementHeader;
    AgreementLine                 agreementLine;

    select firstonly salesAgreementHeader
        where salesAgreementHeader.SalesAgreementId == salesNumberSequenceLoc;
    salesAgreementLine.SalesAgreementId = salesNumberSequenceLoc;

    salesAgreementLine.Agreement = salesAgreementHeader.RecId;

    salesAgreementLine.ItemNumber = ItemId;

    if(name)
    {
        salesAgreementLine.ItemName                         = name;
    }
    else
    {
        salesAgreementLine.ItemName                         = InventTable::find(ItemId).productNameInSystemLanguage();
    }  
    salesAgreementLine.LineNumber                           = lineNum;
    salesAgreementLine.CustAccount                          = salesAgreementHeader.CustAccount;
    salesAgreementLine.AgreementCustomerAccountNumber       = salesAgreementHeader.AgreementCustomerAccountNumber;
    salesAgreementLine.CommitmentType                       = salesAgreementHeader.DefaultCommitmentType;
    salesAgreementLine.CommittedQuantity                    = CommitedQuantity;
    salesAgreementLine.EffectiveDate                        = salesAgreementHeader.DefaultEffectiveDate;
    salesAgreementLine.ProductConfigurationId               = configId;
    salesAgreementLine.ProductSizeId                        = InventSizeId;
    salesAgreementLine.ProductColorId                       = InventColorId;
    salesAgreementLine.ProductStyleId                       = InventStyleId;
    salesAgreementLine.ShippingSiteId                      = InventSiteId;
    salesAgreementLine.ShippingWarehouseId                 = InventLocationId;
    salesAgreementLine.wMSLocationId                        = wMSLocationId;
    salesAgreementLine.LineDiscountPercentage               = LineDiscountPercent;
    salesAgreementLine.PricePerUnit                         = PricePerUnit;
    salesAgreementLine.ExpirationDate                       = salesAgreementHeader.DefaultExpirationDate;
    salesAgreementLine.SalesAgreementId                     = salesAgreementHeader.SalesAgreementId;
    salesAgreementLine.ETGRefSalesAgreementId               = salesAgreementHeader.SalesAgreementId;
    salesAgreementLine.CommissionSalesRepresentativeGroupId = SalesCommissionGroup; 
    salesAgreementLine.LineDiscountAmount                   = LineDiscountAmount;
    salesAgreementLine.Price                                = PricePerUnit;
    salesAgreementLine.ETG_ItemAlternativeName              = ETG_ItemAlternativeName;
    if(ETG_IsGrossWeight == "Yes")
    {
        salesAgreementLine.ETG_IsGrossWeight = NoYes::Yes;
    }
    else
    {
        salesAgreementLine.ETG_IsGrossWeight = NoYes::No;
    }

    if(ETG_PriceType == "None")
    {
        salesAgreementLine.ETG_PriceType = ETG_PriceType::None;
    }
    else if(ETG_PriceType == "Fixed")
    {
        salesAgreementLine.ETG_PriceType = ETG_PriceType::Fixed;
    }
    else
    {
        salesAgreementLine.ETG_PriceType = ETG_PriceType::Floating;
    }
    salesAgreementLine.ETGPriceCondition                    = ETGPriceCondition;

    salesAgreementLine.ETG_UnderDeliveryPct                 = ETG_UnderDeliveryPct;
    salesAgreementLine.ETG_OverDeliveryPct                  = ETG_OverDeliveryPct;

    salesAgreementLine.SalesAgreementLegalEntityId           = curExt();
    salesAgreementLine.InvoiceCustomerAccountNumber           = salesAgreementHeader.InvoiceCustomerAccountNumber;
    salesAgreementLine.UnitSymbol                           = ProductUnitOfMeasure;

    if(ETG_ToleranceAction == "Stop")
    {
        salesAgreementLine.ETG_ToleranceAction = ETG_ToleranceAction::Stop;
    }
    else if(ETG_ToleranceAction == "Warning")
    {
        salesAgreementLine.ETG_ToleranceAction = ETG_ToleranceAction::Warning;
    }
    else
    {
        salesAgreementLine.ETG_ToleranceAction = ETG_ToleranceAction::None;
    }
    salesAgreementLine.ETG_ReleaseOrderLowerLimit           = ETG_ReleaseOrderLowerLimit;
    salesAgreementLine.ETG_ReleaseOrderUpperLimit           = ETG_ReleaseOrderUpperLimit;
    salesAgreementLine.EffectiveDate                        = salesAgreementHeader.DefaultEffectiveDate;
    salesAgreementLine.ExpirationDate                       = salesAgreementHeader.DefaultExpirationDate;
    if(IsPriceInformationMandatory == "Yes")
    {
        salesAgreementLine.IsPriceInformationMandatory = NoYes::Yes;
    }
    else
    {
        salesAgreementLine.IsPriceInformationMandatory = NoYes::No;
    }
    if(maxInforced == "Yes" || maxInforced == "YES")
    {
        salesAgreementLine.IsMaxEnforced                    = NoYes::Yes;
    }
    else
    {
        salesAgreementLine.IsMaxEnforced                    = NoYes::No;
    } 
    salesAgreementLine.ETGReasonCode                   = ETGReasonCode;
    salesAgreementLine.ETG_QualitySpecification        = ETG_QualitySpecification;
    salesAgreementLine.ETGFinalPlaceOfDelivery         = ETGFinalPlaceOfDelivery;
    salesAgreementLine.ETGPriceTolerance               = ETGPriceTolerance;
    salesAgreementLine.ETGFuturePrice                  = ETGFuturePrice;
    salesAgreementLine.ETGPremiumPrice                 = ETGPremiumPrice;
    salesAgreementLine.ETG_QuantityConditions          = QuantityConditions;
    salesAgreementLine.ETGPortOfLoading                = ETGPortOfLoading;
    if(ETGPortOfLoadingDesc)
    {
        salesAgreementLine.ETGPortOfLoadingDesc        = ETGPortOfLoadingDesc;
    }
    else
    {
        select firstonly Description from placeOfLoading where placeOfLoading.PlaceOfLoading == ETGPortOfLoading;
        salesAgreementLine.ETGPortOfLoadingDesc        = placeOfLoading.Description;
    }

    salesAgreementLine.ETGPortOfDischarge              = ETGPortOfDischarge;
    if(ETGPortOfDischargeDesc)
    {
        salesAgreementLine.ETGPortOfDischargeDesc      = ETGPortOfDischargeDesc;
    }
    else
    {
        select firstonly Description from placeOfDischarge where placeOfDischarge.PlaceOfDischarge == ETGPortOfDischarge;
        salesAgreementLine.ETGPortOfDischargeDesc      = placeOfDischarge.Description;
    }


    //salesAgreementLine.DefaultLedgerDimensionDisplayValue     = Vertical + "|"
    //                                                            + BusinessUnit + "|"
    //                                                            + MainCommodity + "|"
    //                                                            + SubCommodity + "|"
    //                                                            + Contract + "|"
    //                                                            + TraderEmployee + "|"
    //                                                            + Intercompany + "|"
    //                                                            + costcenter + "|"
    //                                                            + Line_of_Business + "|"
    //                                                            + Plant_Warehouse_Office + "|"
    //                                                            + Items;

    salesAgreementLine.DefaultLedgerDimensionDisplayValue     = Vertical + "|"
                                                                + BusinessUnit + "|"
                                                                + MainCommodity + "|"
                                                                + SubCommodity + "|"
                                                                + Contract + "|"
                                                                + TraderEmployee + "|"
                                                                + Intercompany + "|"
                                                                + costcenter + "|"
                                                                + Line_of_Business + "|"
                                                                + Plant_Warehouse_Office + "|"
                                                                + Items;

   // Vertical|BusinessUnit|MainCommodity|SubCommodity|Contract|Trader_Employee|Intercompany|Department|Line_of_Businesss|Plant_Warehouse_Office|Item
    //BusinessUnit|Contract|CostCenter|Intercompany|Item|Line_of_Businesss|MainCommodity|Plant_Warehouse_Office|ProfitCenter|Vertical


    if(salesAgreementLine.validateWrite())
    {
        select firstonly RecId from agreementLine
            where agreementLine.Agreement == salesAgreementLine.Agreement
            && agreementLine.LineNumber == salesAgreementLine.LineNumber             
            && agreementLine.ItemDataAreaId == salesAgreementHeader.SellingLegalEntityId;
       if(agreementLine.RecId)
        {
            ttsbegin;
            salesAgreementLine.selectForUpdate();
            salesAgreementLine.update();
            ttscommit;
        }
        else
        {
        salesAgreementLine.insert();
            info(strFmt("Agreement id %1 item %2  line number %3 is successfully created",
                salesAgreementHeader.salesAgreementId,
                salesAgreementHeader.CustAccount,
                salesAgreementLine.ItemNumber,
                salesAgreementLine.LineNumber));
        }
    }
    else
    {
        warning(strFmt("Agreement id %1 item %2  line number %3 is not uploaded",
                salesAgreementHeader.salesAgreementId,
                salesAgreementLine.ItemNumber,
                salesAgreementLine.LineNumber));
    }
}
